import Alamofire

struct APIManager {
    static let baseURL = "https://api.example.com"

    static func executeTrade(symbol: String, quantity: Int, completion: @escaping (Error?, Any?) -> Void) {
        let url = "\(baseURL)/trades?symbol=\(symbol)&quantity=\(quantity)"
        Alamofire.request(url, method: .post).validate().responseJSON { response in
            switch response.result {
            case .success(_):
                completion(nil, response.result.value)
            case .failure(let error):
                completion(error, nil)
            }
        }
    }
}